class Solution:
    def removeDuplicates(self, s, k):
        s = list(s)
        changed = True
        while changed:
            changed = False
            i = 0
            n = len(s)
            while i < n:
                j = i
                while j < n and s[j] == s[i]:
                    j += 1
                if j - i >= k:
                    remove = ((j - i) // k) * k
                    del s[i:i + remove]
                    changed = True
                    break
                i = j
        return ''.join(s)

