var removeDuplicates = function(s, k) {
    const stack = [];
    for (const ch of s) {
        if (stack.length && stack[stack.length - 1][0] === ch) {
            stack[stack.length - 1][1]++;
            if (stack[stack.length - 1][1] === k) stack.pop();
        } else {
            stack.push([ch, 1]);
        }
    }
    return stack.map(([ch, cnt]) => ch.repeat(cnt)).join('');
};
